const applyJob = (job) => {
  if (!loggedUser) return alert("Login Required");

  const employees = JSON.parse(localStorage.getItem("employees")) || [];

  // Get Full Employee details using username/email
  const empDetails =
    employees.find(e => e.email === loggedUser.username) || {};

  const already = applications.some(
    a => a.jobId === job.id && a.empId === loggedUser.empId
  );

  if (already) return alert("You already applied for this job!");

  const newApplication = {
    id: Date.now(),
    jobId: job.id,

    // REQUIRED FIELDS
    empId: loggedUser.empId,
    employeeName: loggedUser.name,
    email: loggedUser.username,
    department: empDetails.department || "Not Assigned",
    jobTitle: job.title,

    appliedDate: new Date().toLocaleDateString(),
    status: "Pending",
  };

  const updated = [...applications, newApplication];
  setApplications(updated);
  localStorage.setItem("applications", JSON.stringify(updated));

  alert("Job Applied Successfully");
};
